function createPlayer(ws) {
  const playerId = `player_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  const spawnX = Math.random() * (gameState.mapWidth - 200) + 100;
  const spawnY = Math.random() * (gameState.mapHeight - 200) + 100;

  const player = {
    id: playerId,
    ws,
    resources: { gold: 500 },
    color: `#${Math.floor(Math.random() * 16777215).toString(16).padStart(6, '0')}`,
    spawnX,
    spawnY,
    alive: true,
  };

  gameState.players.set(playerId, player);

  // Create starting base
  const baseId = createBuilding(playerId, 'base', spawnX, spawnY, true);

  // Create starting units
  const startingUnits = [];
  for (let i = 0; i < 3; i++) {
    const unitId = createUnit(playerId, 'warrior', spawnX + 30 + i * 20, spawnY + 40);
    startingUnits.push(unitId);
  }

  return { playerId, baseId, startingUnits };
}

function createUnit(playerId, unitType, x, y) {
  const template = UNIT_TYPES[unitType];
  if (!template) return null;

  const unitId = `unit_${gameState.nextUnitId++}`;
  const unit = {
    id: unitId,
    playerId,
    type: unitType,
    x,
    y,
    hp: template.hp,
    maxHp: template.hp,
    attack: template.attack,
    defense: template.defense,
    speed: template.speed,
    range: template.range,
    state: 'idle', // idle, moving, attacking, dead
    targetX: null,
    targetY: null,
    targetUnitId: null,
    lastAttackTime: 0,
  };

  gameState.units.set(unitId, unit);
  return unitId;
}

function createBuilding(playerId, buildingType, x, y, instant = false) {
  const template = BUILDING_TYPES[buildingType];
  if (!template) return null;

  const buildingId = `building_${gameState.nextBuildingId++}`;
  const building = {
    id: buildingId,
    playerId,
    type: buildingType,
    x,
    y,
    hp: instant ? template.hp : 1,
    maxHp: template.hp,
    buildTime: template.buildTime,
    buildStartTime: instant ? 0 : Date.now(),
    completed: instant,
    produces: template.produces,
    incomeRate: template.incomeRate || 0,
    trainingQueue: [],
    rallyX: x,
    rallyY: y + 40,
  };

  gameState.buildings.set(buildingId, building);
  return buildingId;
}

function distance(x1, y1, x2, y2) {
  return Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
}

function clamp(val, min, max) {
  return Math.min(Math.max(val, min), max);
}

function deductResources(player, cost) {
  for (const [resource, amount] of Object.entries(cost)) {
    if ((player.resources[resource] || 0) < amount) return false;
  }
  for (const [resource, amount] of Object.entries(cost)) {
    player.resources[resource] -= amount;
  }
  return true;
}

function handleCommand(playerId, command) {
  const player = gameState.players.get(playerId);
  if (!player || !player.alive) return { error: 'Player not found or eliminated' };

  switch (command.type) {
    case 'move':
      return handleMove(playerId, command);
    case 'attack':
      return handleAttack(playerId, command);
    case 'build':
      return handleBuild(playerId, command);
    case 'train':
      return handleTrain(playerId, command);
    case 'set_rally':
      return handleSetRally(playerId, command);
    case 'stop':
      return handleStop(playerId, command);
    case 'get_state':
      return getPlayerGameState(playerId);
    default:
      return { error: `Unknown command type: ${command.type}` };
  }
}

function handleMove(playerId, command) {
  const { unitIds, targetX, targetY } = command;
  if (!unitIds || !Array.isArray(unitIds) || targetX == null || targetY == null) {
    return { error: 'Invalid move command. Required: unitIds (array), targetX, targetY' };
  }

  const clampedX = clamp(targetX, 0, gameState.mapWidth);
  const clampedY = clamp(targetY, 0, gameState.mapHeight);
  const movedUnits = [];

  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit || unit.playerId !== playerId || unit.state === 'dead') continue;

    unit.state = 'moving';
    unit.targetX = clampedX;
    unit.targetY = clampedY;
    unit.targetUnitId = null;
    movedUnits.push(unitId);
  }

  broadcastToAll({
    event: 'units_moving',
    playerId,
    unitIds: movedUnits,
    targetX: clampedX,
    targetY: clampedY,
  });

  return { success: true, movedUnits };
}

function handleAttack(playerId, command) {
  const { unitIds, targetUnitId, targetBuildingId } = command;
  if (!unitIds || !Array.isArray(unitIds)) {
    return { error: 'Invalid attack command. Required: unitIds (array), targetUnitId or targetBuildingId' };
  }

  const targetId = targetUnitId || targetBuildingId;
  const isBuilding = !!targetBuildingId;
  const target = isBuilding ? gameState.buildings.get(targetId) : gameState.units.get(targetId);

  if (!target) return { error: 'Target not found' };
  if (target.playerId === playerId) return { error: 'Cannot attack own units/buildings' };
  if (!isBuilding && target.state === 'dead') return { error: 'Target is already dead' };

  const attackingUnits = [];

  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit || unit.playerId !== playerId || unit.state === 'dead') continue;

    unit.state = 'attacking';
    unit.targetUnitId = targetId;
    unit.targetX = target.x;
    unit.targetY = target.y;
    unit._targetIsBuilding = isBuilding;
    attackingUnits.push(unitId);
  }

  broadcastToAll({
    event: 'units_attacking',
    playerId,
    unitIds: attackingUnits,
    targetId,
    isBuilding,
  });

  return { success: true, attackingUnits };
}

function handleBuild(playerId, command) {
  const { buildingType, x, y } = command;
  if (!buildingType || x == null || y == null) {
    return { error: 'Invalid build command. Required: buildingType, x, y' };
  }

  const template = BUILDING_TYPES[buildingType];
  if (!template) return { error: `Unknown building type: ${buildingType}` };
  if (buildingType === 'base') return { error: 'Cannot build additional bases' };

  const player = gameState.players.get(playerId);
  if (!deductResources(player, template.cost)) {
    return { error: 'Insufficient resources', required: template.cost, current: player.resources };
  }

  // Check for overlapping buildings
  for (const [, building] of gameState.buildings) {
    if (distance(building.x, building.y, x, y) < 40) {
      // Refund resources
      for (const [resource, amount] of Object.entries(template.cost)) {
        player.resources[resource] += amount;
      }
      return { error: 'Too close to another building' };
    }
  }

  const clampedX = clamp(x, 20, gameState.mapWidth - 20);
  const clampedY = clamp(y, 20, gameState.mapHeight - 20);
  const buildingId = createBuilding(playerId, buildingType, clampedX, clampedY);

  broadcastToAll({
    event: 'building_started',
    playerId,
    buildingId,
    buildingType,
    x: clampedX,
    y: clampedY,
    buildTime: template.buildTime,
  });

  return { success: true, buildingId, remainingResources: player.resources };
}

function handleTrain(playerId, command) {
  const { buildingId, unitType } = command;
  if (!buildingId || !unitType) {
    return { error: 'Invalid train command. Required: buildingId, unitType' };
  }

  const building = gameState.buildings.get(buildingId);
  if (!building) return { error: 'Building not found' };
  if (building.playerId !== playerId) return { error: 'Not your building' };
  if (!building.completed) return { error: 'Building not yet completed' };
  if (!building.produces.includes(unitType)) {
    return { error: `This building cannot produce ${unitType}` };
  }

  const unitTemplate = UNIT_TYPES[unitType];
  if (!unitTemplate) return { error: `Unknown unit type: ${unitType}` };

  const player = gameState.players.get(playerId);
  if (!deductResources(player, unitTemplate.cost)) {
    return { error: 'Insufficient resources', required: unitTemplate.cost, current: player.resources };
  }

  const trainTime = 3000; // 3 seconds per unit
  building.trainingQueue.push({
    unitType,
    startTime: Date.now(),
    trainTime,
    completed: false,
  });

  sendToPlayer(playerId, {
    event: 'training_started',
    buildingId,
    unitType,
    queueLength: building.trainingQueue.length,
    remainingResources: player.resources,
  });

  return { success: true, queueLength: building.trainingQueue.length };
}

function handleSetRally(playerId, command) {
  const { buildingId, x, y } = command;
  if (!buildingId || x == null || y == null) {
    return { error: 'Invalid set_rally command. Required: buildingId, x, y' };
  }

  const building = gameState.buildings.get(buildingId);
  if (!building) return { error: 'Building not found' };
  if (building.playerId !== playerId) return { error: 'Not your building' };

  building.rallyX = clamp(x, 0, gameState.mapWidth);
  building.rallyY = clamp(y, 0, gameState.mapHeight);

  return { success: true, rallyX: building.rallyX, rallyY: building.rallyY };
}

function handleStop(playerId, command) {
  const { unitIds } = command;
  if (!unitIds || !Array.isArray(unitIds)) {
    return { error: 'Invalid stop command. Required: unitIds (array)' };
  }

  const stoppedUnits = [];
  for (const unitId of unitIds) {
    const unit = gameState.units.get(unitId);
    if (!unit || unit.playerId !== playerId || unit.state === 'dead') continue;

    unit.state = 'idle';
    unit.targetX = null;
    unit.targetY = null;
    unit.targetUnitId = null;
    stoppedUnits.push(unitId);
  }

  broadcastToAll({
    event: 'units_stopped',
    playerId,
    unitIds: stoppedUnits,
  });

  return { success: true, stoppedUnits };
}

function getPlayerGameState(playerId) {
  const player = gameState.players.get(playerId);
  const units = [];
  const buildings = [];
  const enemyUnits = [];
  const enemyBuildings = [];

  for (const [, unit] of gameState.units) {
    if (unit.state === 'dead') continue;
    const unitData = { ...unit };
    if (unit.playerId === playerId) {
      units.push(unitData);
    } else {
      enemyUnits.push(unitData);
    }
  }

  for (const [, building] of gameState.buildings) {
    if (building.hp <= 0) continue;
    const buildingData = { ...building };
    delete buildingData.trainingQueue; // Don't reveal enemy training queues
    if (building.playerId === playerId) {
      buildingData.trainingQueue = building.trainingQueue;
      buildings.push(buildingData);
    } else {
      enemyBuildings.push(buildingData);
    }
  }

  return {
    success: true,
    playerId,
    resources: player.resources,
    units,
    buildings,
    enemyUnits,
    enemyBuildings,
    mapWidth: gameState.mapWidth,
    mapHeight: gameState.mapHeight,
  };
}

